import spyne
from spyne import Application, ServiceBase, rpc
from spyne.protocol.soap import Soap11
from spyne.server.wsgi import WsgiApplication
from spyne.model.fault import Fault

# Define the service operations
class FinancialServices(ServiceBase):
    @rpc(String, _returns=String)
    def getBalance(ctx, account_id):
        # Implement business logic for getting balance
        return "100.00"

    @rpc(String, String, _returns=String)
    def transferFunds(ctx, from_account_id, to_account_id):
        # Implement business logic for transferring funds
        return "Transfer successful"

    @rpc(String, _returns=String)
    def getAccountInfo(ctx, account_id):
        # Implement business logic for getting account info
        return "Account information"

# Define the SOAP server
application = Application([FinancialServices],
                          tns="http://spyne.io/examples/financial",
                          in_protocol=Soap11(validator='lxml'),
                          out_protocol=Soap11())
server = WsgiApplication(application)

# Prevent SOAP action spoofing
def prevent_soap_action_spoofing(ctx):
    if ctx.in_header.get("SOAPAction") is None:
        raise Fault("Missing SOAPAction header", "Client.BadRequest")

server.add_filter(prevent_soap_action_spoofing)